const fs = require('fs');
const path = require('path');

const projectRoot = path.resolve(__dirname);

const files = [
  {
    path: 'src/app/[state]/[city]/page.tsx',
    content: Buffer.from('', 'base64').toString('utf8'),
  },
  {
    path: 'src/app/[state]/page.tsx',
    content: Buffer.from('', 'base64').toString('utf8'),
  },
  {
    path: 'src/app/[state]/[city]/[service]/page.tsx',
    content: Buffer.from('', 'base64').toString('utf8'),
  },
  {
    path: 'src/app/sitemap.ts',
    content: Buffer.from('', 'base64').toString('utf8'),
  },
];

let applied = 0;
for (const f of files) {
  const target = path.join(projectRoot, f.path);
  const dir = path.dirname(target);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(target, f.content, 'utf8');
  console.log(`  ✅ ${f.path}`);
  applied++;
}

console.log(`\nPatch v26 applied — ${applied} files updated.`);
console.log('Next: npm run build && git add -A && git commit -m "v26: live Supabase data for state/city/service pages + dynamic sitemap" && git push');
